import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Login from "./components/Login";
import Signup from "./components/Signup";
import Dashboard from "./components/Dashboard"; // For users
import AdminDashboard from "./components/AdminDashboard"; // For admin
import BookList from "./components/BookList";
import Borrow from "./components/Borrow";
import Return from "./components/Return";
import UserProfile from "./components/UserProfile";
import History from "./components/History";
import ManageBooks from "./components/ManageBooks";
import UserDetails from "./components/UserDetails";
import BorrowRecords from "./components/BorrowRecords";

const App = () => {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/signup" element={<Signup />} />

        {/* User Dashboard */}
        <Route path="/dashboard" element={<Dashboard />}>
          <Route path="books" element={<BookList />} />
          <Route path="borrow" element={<Borrow />} />
          <Route path="return" element={<Return />} />
          <Route path="profile" element={<UserProfile />} />
          <Route path="history" element={<History />} />
        </Route>

        {/* Admin Dashboard */}
        <Route path="/admin" element={<AdminDashboard />}>
          <Route path="manage-books" element={<ManageBooks />} />
          <Route path="user-details" element={<UserDetails />} />
          <Route path="borrow-records" element={<BorrowRecords />} />
        </Route>
      </Routes>
    </Router>
  );
};

export default App;
